/**
 * @fileoverview Toggle component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, ARIA attrs, default config
 *   helpers.js   — label resolution utility
 *   state.js     — pure SM transitions + reactive state wiring
 *   view.js      — DOM setup / teardown + SM effects
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/Toggle
 */

import { default as razyui } from '../../index.js';
import { StateMachine } from '../shared/StateMachine.js';
import { ToggleDef as DEF } from '../Toggle.def.js';

import { DEFAULTS, CLS }                              from './constants.js';
import { resolveLabel }                                from './helpers.js';
import { TOGGLE_TRANSITIONS, createReactiveState }     from './state.js';
import { SM_EFFECTS, setupDOM, cleanupDOM }            from './view.js';
import { createHandlerCtx, bindEvents }                from './events.js';
import { emitEvent }                                   from '../shared/emitEvent.js';

/**
 * Toggle — on/off switch component (JIT-compatible)
 *
 * Enhances a container element into an accessible toggle switch with
 * ARIA `role="switch"`, keyboard support (Space, Enter), and reactive state.
 *
 * Features:
 *   - Auto ARIA setup (role=switch, aria-checked)
 *   - Keyboard activation (Space, Enter)
 *   - Customizable labels (on/off text)
 *   - Three sizes: sm, md (default), lg
 *   - Disabled state
 *   - Callbacks: onChange
 *   - Programmatic API: toggle(), getControl()
 *
 * @param {string|Element} selector — CSS selector or Element for the toggle container
 * @param {object}   [config]
 * @param {boolean}  [config.checked]   — initial state (default false)
 * @param {boolean}  [config.disabled]  — initial disabled state (default false)
 * @param {string}   [config.size]      — 'sm' | 'md' | 'lg' (default 'md')
 * @param {string}   [config.labelOn]   — label text when on
 * @param {string}   [config.labelOff]  — label text when off
 * @param {function} [config.onChange]   — (checked: boolean) => void
 */
const Toggle = class {
    #root  = null;
    #destroyed = false;
    #track = null;
    #thumb = null;
    #label = null;
    #sm    = null;
    #config = {};
    #stateRef  = null;
    #setState  = null;
    #uid       = 0;
    #eventAC   = null;
    #hiddenInput = null;

    static #counter = 0;

    constructor(selector, config = {}) {
        const root = razyui(selector);

        if (!root.length) {
            console.warn('Toggle: element not found \u2192', selector);
            return;
        }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#uid    = ++Toggle.#counter;

        this.#init();
    }

    #init() {
        const root   = this.#root;
        const uid    = this.#uid;
        const config = this.#config;

        // 1. View: build DOM structure
        const { track, thumb, label } = setupDOM(root, uid, config);
        this.#track = track;
        this.#thumb = thumb;
        this.#label = label;

        // 2. State machine
        const smConfig = { ...TOGGLE_TRANSITIONS, effects: SM_EFFECTS };
        const sm = new StateMachine(smConfig, { root, track, thumb });
        this.#sm = sm;

        // 3. Reactive state
        const { ref, setState } = createReactiveState(razyui.state, sm);
        this.#stateRef = ref;
        this.#setState = setState;

        // 4. Events
        const ctx = createHandlerCtx(() => ({
            checked:  this.#stateRef.checked,
            disabled: this.#sm.current === 'disabled',
            toggle:   () => this.toggle(),
        }));
        this.#eventAC = bindEvents(track, ctx);

        // 5. Apply initial state
        if (config.disabled) {
            const initialState = config.checked ? 'on' : 'off';
            sm.reset(initialState);
            SM_EFFECTS[initialState]({ track, thumb });
            sm.reset('disabled');
            SM_EFFECTS.disabled({ root, track });
        } else if (config.checked) {
            this.#setState({ checked: true });
        }

        // 6. Update label
        this.#updateLabel();

        // 7. Hidden input for native form submission
        if (config.name) {
            const hidden = document.createElement('input');
            hidden.type = 'hidden';
            hidden.name = config.name;
            hidden.value = config.checked ? 'on' : '';
            root[0].appendChild(hidden);
            this.#hiddenInput = hidden;
        }
    }

    #updateLabel() {
        if (!this.#label) return;
        const text = resolveLabel(
            this.#stateRef.checked,
            this.#config.labelOn,
            this.#config.labelOff,
        );
        if (text) this.#label[0].textContent = text;
    }

    // ── Public API ──

    /** Toggle the switch. */
    toggle() {
        if (this.#sm.current === 'disabled') return;

        const next = !this.#stateRef.checked;
        this.#setState({ checked: next });
        this.#updateLabel();
        if (this.#hiddenInput) this.#hiddenInput.value = next ? 'on' : '';

        emitEvent(this.#root[0], 'change', { value: next, checked: next });
        if (typeof this.#config.onChange === 'function') {
            this.#config.onChange.call(this, next);
        }
    }

    /** Get current checked state. */
    get checked() {
        return this.#stateRef.checked;
    }

    /** Set checked state programmatically. */
    set checked(value) {
        const next = !!value;
        if (next === this.#stateRef.checked) return;
        this.#setState({ checked: next });
        this.#updateLabel();
        if (this.#hiddenInput) this.#hiddenInput.value = next ? 'on' : '';

        emitEvent(this.#root[0], 'change', { value: next, checked: next });
        if (typeof this.#config.onChange === 'function') {
            this.#config.onChange.call(this, next);
        }
    }

    /** Enable or disable the toggle. */
    setDisabled(disabled) {
        const sm = this.#sm;
        if (disabled && sm.current !== 'disabled') {
            sm.reset('disabled');
            SM_EFFECTS.disabled({
                root: this.#root,
                track: this.#track,
            });
        } else if (!disabled && sm.current === 'disabled') {
            const target = this.#stateRef.checked ? 'on' : 'off';
            sm.send(this.#stateRef.checked ? 'ENABLE_ON' : 'ENABLE_OFF');
        }
    }

    setInvalid(invalid) {
        this.#root.toggleClass(CLS.INVALID, !!invalid);
        this.#root[0][invalid ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    focus() { this.#track[0]?.focus(); }
    blur()  { this.#track[0]?.blur(); }

    clear() { this.checked = false; }

    /**
     * Get a reactive control object with get/set properties.
     * @returns {object} ctrl
     */
    getControl() {
        const self = this;
        return {
            get value() { return self.checked; },
            set value(v) { self.checked = v; },
            get checked() { return self.checked; },
            set checked(v) { self.checked = v; },
            get disabled() { return self.#sm.current === 'disabled'; },
            set disabled(v) { self.setDisabled(v); },
            get name() { return self.#config.name ?? ''; },
            set name(v) { self.#config.name = v; if (self.#hiddenInput) self.#hiddenInput.name = v; },
            get labelOn() { return self.#config.labelOn; },
            set labelOn(v) { self.#config.labelOn = v; if (self.#label) self.#label[0].textContent = self.#stateRef.checked ? v : self.#config.labelOff; },
            get labelOff() { return self.#config.labelOff; },
            set labelOff(v) { self.#config.labelOff = v; if (self.#label) self.#label[0].textContent = self.#stateRef.checked ? self.#config.labelOn : v; },
            get required() { return self.#config.required ?? false; },
            set required(v) { self.#config.required = !!v; if (self.#hiddenInput) self.#hiddenInput.required = !!v; self.#root[0].setAttribute('aria-required', String(!!v)); },
            toggle:            () => self.toggle(),
            setDisabled:       d => self.setDisabled(d),
            setInvalid:        v => self.setInvalid(v),
            checkValidity:     () => self.#hiddenInput ? self.#hiddenInput.checkValidity() : true,
            reportValidity:    () => self.#hiddenInput ? self.#hiddenInput.reportValidity() : true,
            setCustomValidity: (m) => { if (self.#hiddenInput) self.#hiddenInput.setCustomValidity(m || ''); self.setInvalid(!!m); },
            get label() { return self.#root[0].getAttribute('aria-label'); },
            set label(v) { v ? self.#root[0].setAttribute('aria-label', v) : self.#root[0].removeAttribute('aria-label'); },
            get labelledby() { return self.#root[0].getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#root[0].setAttribute('aria-labelledby', v) : self.#root[0].removeAttribute('aria-labelledby'); },
            get describedby() { return self.#root[0].getAttribute('aria-describedby'); },
            set describedby(v) { v ? self.#root[0].setAttribute('aria-describedby', v) : self.#root[0].removeAttribute('aria-describedby'); },
            focus:   () => self.focus(),
            blur:    () => self.blur(),
            clear:   () => self.clear(),
            destroy: () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Cleanup — remove DOM, classes, and event listeners. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        if (this.#hiddenInput) { this.#hiddenInput.remove(); this.#hiddenInput = null; }
        cleanupDOM(this.#root);
        this.#sm = null;
    }
};

export default Toggle;
