/**
 * @fileoverview Toggle state — pure state machine transitions + reactive state wiring.
 * @module module/Toggle/state
 */

/**
 * Pure state machine transition map for toggle states.
 * Side-effect free — paired with view effects in view.js.
 */
export const TOGGLE_TRANSITIONS = {
    initial: 'off',
    states: {
        off:      { on: { TOGGLE: 'on', DISABLE: 'disabled' } },
        on:       { on: { TOGGLE: 'off', DISABLE: 'disabled' } },
        disabled: { on: { ENABLE_OFF: 'off', ENABLE_ON: 'on' } },
    },
};

/**
 * Create reactive toggle state wired to a StateMachine.
 *
 * @param {Function} stateFn — `razyui.state` factory
 * @param {import('../shared/StateMachine.js').StateMachine} sm — toggle state machine
 * @returns {{ ref: object, setState: Function }}
 */
export function createReactiveState(stateFn, sm) {
    const stateSet = stateFn({ checked: false });
    const ref      = stateSet[0];
    const setState = stateSet[1];

    stateSet.effect(() => {
        const checked = ref.checked;
        if (checked && sm.current === 'off') sm.send('TOGGLE');
        else if (!checked && sm.current === 'on') sm.send('TOGGLE');
    });

    return { ref, setState };
}
