/**
 * @fileoverview Toggle view — DOM setup / teardown and state-machine effects.
 * @module module/Toggle/view
 */

import { CLS, ARIA, PART } from './constants.js';

// ═══════════════════════════════════════
//  State Machine Effects (DOM updates)
// ═══════════════════════════════════════

export const SM_EFFECTS = {
    /** Entry effect — toggle is ON */
    on({ track, thumb }) {
        track.addClass(CLS.ACTIVE).setAttr({ 'aria-checked': 'true' });
        thumb.addClass(CLS.ACTIVE);
    },

    /** Entry effect — toggle is OFF */
    off({ track, thumb }) {
        track.removeClass(CLS.ACTIVE).setAttr({ 'aria-checked': 'false' });
        thumb.removeClass(CLS.ACTIVE);
    },

    /** Entry effect — toggle becomes disabled */
    disabled({ root, track }) {
        root.addClass(CLS.DISABLED);
        track.setAttr({ 'aria-disabled': 'true', tabindex: '-1' });
    },

    /** Exit effect — leaving disabled */
    'disabled:exit'({ root, track }) {
        root.removeClass(CLS.DISABLED);
        track.removeAttr('aria-disabled').setAttr({ tabindex: '0' });
    },
};

// ═══════════════════════════════════════
//  DOM Setup
// ═══════════════════════════════════════

/**
 * Build the toggle DOM structure inside the root element.
 *
 * @param {Elements} root — razyui-wrapped root element
 * @param {number} uid — unique instance id
 * @param {object} config — { size, variant, labelOn, labelOff, checked }
 * @returns {{ track: Elements, thumb: Elements, label: Elements|null }}
 */
export function setupDOM(root, uid, config) {
    const { size, variant } = config;

    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    if (size === 'sm') {
        PART.SM_ROOT.apply(root);
    } else if (size === 'lg') {
        PART.LG_ROOT.apply(root);
    }

    // Create track
    const track = PART.TRACK.create({
        role: ARIA.SWITCH,
        'aria-checked': 'false',
        tabindex: '0',
    });
    track[0].id = `toggle-${uid}`;
    root.append(track);

    // Create thumb inside track
    const thumb = PART.THUMB.create();
    track.append(thumb);

    // Create label if configured
    let label = null;
    const labelText = config.labelOn || config.labelOff;
    if (labelText) {
        label = PART.LABEL.create();
        root.append(label);
    }

    return { track, thumb, label };
}

// ═══════════════════════════════════════
//  DOM Teardown
// ═══════════════════════════════════════

/**
 * Remove all attributes, roles, and classes added by the Toggle.
 *
 * @param {Elements} root
 */
export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT, CLS.DISABLED);
    PART.ROOT.unapply(root);
    PART.SM_ROOT.unapply(root);
    PART.LG_ROOT.unapply(root);

    // Remove generated children
    const el = root[0];
    while (el.firstChild) el.removeChild(el.firstChild);
}
