/**
 * @fileoverview Toggle constants — CSS classes, ARIA attributes, selectors, defaults.
 * @module module/Toggle/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:     'toggle',
    TRACK:    'toggle-track',
    THUMB:    'toggle-thumb',
    LABEL:    'toggle-label',
    ACTIVE:   'is-on',
    DISABLED: 'is-disabled',
    INVALID:  'is-invalid',
});

/** ARIA role values */
export const ARIA = Object.freeze({
    SWITCH: 'switch',
});

/** DOM selectors */
export const SEL = Object.freeze({
    ROOT:  '.toggle',
    TRACK: '.toggle-track',
    THUMB: '.toggle-thumb',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    checked: false,
    disabled: false,
    size: 'md',
    variant: null,
    labelOn: null,
    labelOff: null,
});

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('Toggle', {
    ROOT        : { class: 'toggle-container', aliases: ['toggle', 'root', 'container'] },
    TRACK       : { class: 'toggle-track', aliases: ['track'], tag: 'span' },
    THUMB       : { class: 'toggle-thumb', aliases: ['thumb', 'knob'], tag: 'span' },
    LABEL       : { class: 'toggle-label', aliases: ['label', 'text'], tag: 'span' },
    SM_ROOT     : { class: 'toggle-container-sm' },
    LG_ROOT     : { class: 'toggle-container-lg' },
});

PART.ROOT.jit     = 'relative inline-flex items-center gap-[var(--tg-gap)] cursor-pointer select-none [font-family:inherit] text-[var(--tg-font-size)] fg-[var(--tg-text)] {is-disabled}:opacity-50 {is-disabled}:cursor-not-allowed';
PART.TRACK.jit    = 'relative inline-flex items-center shrink-0 w-[var(--tg-track-w)] h-[var(--tg-track-h)] rounded-full bg-[var(--tg-track-bg)] [border:1px_solid_var(--tg-border)] [transition:background_.2s,border-color_.2s] cursor-pointer {is-on}:[background:var(--tg-track-bg-on)] {is-on}:[border-color:var(--tg-border-on)] focus-visible:[outline:2px_solid_var(--tg-track-bg-on)] focus-visible:[outline-offset:2px] hover:opacity-80 ^{is-disabled}:cursor-not-allowed ^{is-disabled}:hover:opacity-100';
PART.THUMB.jit    = 'absolute [top:50%] left-[var(--tg-thumb-inset)] w-[var(--tg-thumb-size)] h-[var(--tg-thumb-size)] rounded-full bg-[var(--tg-thumb-bg)] shadow-[var(--tg-shadow-sm)] [transition:transform_.2s_cubic-bezier(0.4,0,0.2,1)] [transform:translateY(-50%)] {is-on}:[transform:translateX(calc(var(--tg-track-w)_-_var(--tg-thumb-size)_-_var(--tg-thumb-inset)_*_2_-_2px))_translateY(-50%)]';
PART.LABEL.jit    = 'fg-[var(--tg-text)] [line-height:var(--tg-track-h)] ' + TRANSITION_COLORS;
PART.SM_ROOT.jit  = '[--tg-track-w:32px] [--tg-track-h:18px] [--tg-thumb-size:14px] [--tg-thumb-inset:2px] [--tg-font-size:0.8rem]';
PART.LG_ROOT.jit  = '[--tg-track-w:56px] [--tg-track-h:30px] [--tg-thumb-size:24px] [--tg-thumb-inset:2px] [--tg-font-size:1rem]';