/**
 * @fileoverview Toggle component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * event handler abstractions, and Custom Element metadata.
 *
 * @module module/Toggle.def
 */

import razyui from '../index.js';
import { PART } from './Toggle/constants.js';

/**
 * Definition object for the Toggle component.
 * @type {object}
 */
export const ToggleDef = {
    name: 'Toggle',
    tag: 'rui-toggle',

    // ═════════════════════════════════════
    //  Design Tokens
    // ═════════════════════════════════════
    tokens: {
        prefix: 'tg',
        tokens: {
            'font-size':    { ref: 'font.size-sm',       description: 'Label font size' },
            'gap':          { ref: 'spacing.2',           description: 'Gap between track and label' },
            'track-w':      { value: '44px',              description: 'Track width' },
            'track-h':      { value: '24px',              description: 'Track height' },
            'track-bg':     { ref: 'color.bg-inset',      description: 'Track background (off)' },
            'track-bg-on':  { ref: 'color.accent',        description: 'Track background (on)' },
            'thumb-size':   { value: '18px',              description: 'Thumb diameter' },
            'thumb-inset':  { value: '2px',               description: 'Thumb inset from track edge' },
            'thumb-bg':     { value: '#fff',              description: 'Thumb fill color' },
            'border':       { ref: 'color.border',        description: 'Track border color (off)' },
            'border-on':    { ref: 'color.accent',        description: 'Track border color (on)' },
            'text':         { ref: 'color.text',          description: 'Label text color' },
            'text-muted':   { ref: 'color.text-muted',    description: 'Muted label color' },
            'shadow-sm':    { ref: 'shadow.sm',           description: 'Thumb shadow' },
            'font-stack':   { ref: 'font.family',         description: 'Font family' },
        },
    },

    // ═════════════════════════════════════
    //  State Machine
    // ═════════════════════════════════════
    states: {
        initial: 'off',
        states: {
            off:      { on: { TOGGLE: 'on', DISABLE: 'disabled' } },
            on:       { on: { TOGGLE: 'off', DISABLE: 'disabled' } },
            disabled: { on: { ENABLE_OFF: 'off', ENABLE_ON: 'on' } },
        },
        effects: {
            on(ctx) {
                const { track, thumb } = ctx;
                razyui(track).setAttr({ 'aria-checked': 'true' }).addClass('is-on');
                razyui(thumb).addClass('is-on');
            },
            off(ctx) {
                const { track, thumb } = ctx;
                razyui(track).setAttr({ 'aria-checked': 'false' }).removeClass('is-on');
                razyui(thumb).removeClass('is-on');
            },
            disabled(ctx) {
                razyui(ctx.root).addClass('is-disabled');
                razyui(ctx.track).setAttr({ 'aria-disabled': 'true', tabindex: '-1' });
            },
            'disabled:exit'(ctx) {
                razyui(ctx.root).removeClass('is-disabled');
                razyui(ctx.track).removeAttr('aria-disabled').setAttr({ tabindex: '0' });
            },
        },
    },

    // ═════════════════════════════════════
    //  Template Slots
    // ═════════════════════════════════════
    template: {
        slots: {
            root:  { element: 'label', classes: ['toggle'],       role: null },
            track: { element: 'span',  classes: ['toggle-track'], role: 'switch' },
            thumb: { element: 'span',  classes: ['toggle-thumb'], role: null },
            label: { element: 'span',  classes: ['toggle-label'], role: null },
        },
    },

    // ═════════════════════════════════════
    //  JIT Parts
    // ═════════════════════════════════════
    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.TRACK]: PART.TRACK,
        [PART.THUMB]: PART.THUMB,
        [PART.LABEL]: PART.LABEL,
        [PART.SM_ROOT]: PART.SM_ROOT,
        [PART.LG_ROOT]: PART.LG_ROOT,
    },

    styles: {},

    // ═════════════════════════════════════
    //  Event Handlers
    // ═════════════════════════════════════
    handlers: {
        track: {
            click(ctx, e) {
                e.preventDefault();
                if (ctx.disabled) return;
                ctx.toggle();
            },
            keydown(ctx, e) {
                if (ctx.disabled) return;
                if (e.key === ' ' || e.key === 'Enter') {
                    e.preventDefault();
                    ctx.toggle();
                }
            },
        },
    },

    // ═════════════════════════════════════
    //  Variants
    // ═════════════════════════════════════
    variants: {},

    // ═════════════════════════════════════
    //  Custom Element
    // ═════════════════════════════════════
    observedAttrs: ['checked', 'disabled', 'size', 'label-on', 'label-off'],
    attrMap: {
        checked:     'checked',
        disabled:    'disabled',
        size:        'size',
        'label-on':  'labelOn',
        'label-off': 'labelOff',
    },
};

export default ToggleDef;
