/**
 * @fileoverview Toggle events — centralised event binding via AbortController.
 * @module module/Toggle/events
 */

import razyui from '../../index.js';
import { ToggleDef as DEF } from '../Toggle.def.js';

/**
 * Create the handler context object consumed by DEF event dispatchers.
 *
 * @param {Function} provider — () => { checked, toggle, disabled }
 * @returns {object} handler context with live getters
 */
export function createHandlerCtx(provider) {
    return {
        get checked()  { return provider().checked; },
        get disabled() { return provider().disabled; },
        toggle()       { provider().toggle(); },
    };
}

/**
 * Bind click and keyboard events on the toggle track.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {Elements} track — the track element
 * @param {object} ctx — handler context from createHandlerCtx
 * @returns {AbortController}
 */
export function bindEvents(track, ctx) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    track.on('click',   e => DEF.handlers.track.click(ctx, e),   opts);
    track.on('keydown', e => DEF.handlers.track.keydown(ctx, e), opts);

    return ac;
}
